<template><div class="panel"><div class="section-head"><div><h2>{{ t('routes.title') }}</h2><p>{{ t('routes.description') }}</p></div><el-button v-if="auth.hasPermission('model:route:create')" type="primary" @click="open()">{{ t('routes.add') }}</el-button></div><el-table :data="rows"><el-table-column prop="featureCode" :label="t('routes.featureCode')"/><el-table-column prop="name" :label="t('common.name')"/><el-table-column :label="t('routes.candidates')"><template #default="s">{{modelNames(s.row.candidateModelIds)}}</template></el-table-column><el-table-column :label="t('routes.thinking')"><template #default="s">{{s.row.enableThinking?t('common.enabled'):t('common.close')}}</template></el-table-column><el-table-column :label="t('common.operation')"><template #default="s"><el-button link type="primary" @click="open(s.row)">{{ t('common.edit') }}</el-button><el-button link type="danger" @click="remove(s.row)">{{ t('common.delete') }}</el-button></template></el-table-column></el-table><el-dialog v-model="visible" :title="form.id?t('routes.edit'):t('routes.add')"><el-form label-width="100px"><el-form-item :label="t('routes.featureCode')"><el-input v-model="form.featureCode" :placeholder="t('routes.example')"/></el-form-item><el-form-item :label="t('common.name')"><el-input v-model="form.name"/></el-form-item><el-form-item :label="t('routes.candidates')"><el-select v-model="form.candidateModelIds" multiple><el-option v-for="item in models" :key="item.id" :label="item.name" :value="item.id"/></el-select></el-form-item><el-form-item :label="t('routes.thinking')"><el-switch v-model="form.enableThinking"/></el-form-item><el-form-item :label="t('common.enabled')"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="save">{{ t('common.save') }}</el-button></template></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{useI18n}from'vue-i18n';import http from'../api/http';import{useAuthStore}from'../stores/auth';const{t}=useI18n();const auth=useAuthStore(),rows=ref([]),models=ref([]),visible=ref(false),form=reactive({id:null,featureCode:'',name:'',candidateModelIds:[],enableThinking:false,enabled:true});async function load(){[rows.value,models.value]=await Promise.all([http.get('/models/routes').then(r=>r.data),http.get('/models').then(r=>r.data)])}/** 打开路由窗口。 */function open(row){Object.assign(form,row?{...row,candidateModelIds:[...row.candidateModelIds]}:{id:null,featureCode:'',name:'',candidateModelIds:[],enableThinking:false,enabled:true});visible.value=true}/** 保存能力路由。 */async function save(){form.id?await http.put(`/models/routes/${form.id}`,form):await http.post('/models/routes',form);visible.value=false;await load();ElMessage.success(t('common.successSaved'))}/** 删除能力路由。 */async function remove(row){await ElMessageBox.confirm(t('common.confirmDelete',{name:row.name}),t('common.deleteConfirm'),{type:'warning'});await http.delete(`/models/routes/${row.id}`);await load();ElMessage.success(t('common.successDeleted'))}function modelNames(ids){return(ids||[]).map(id=>models.value.find(item=>item.id===id)?.name||id).join(' → ')}onMounted(load)</script>
